import os
from pathlib import Path

def create_uni_structure():
    home = Path.home() / 'MUST'
    year = home / 'Year1'

    courses = {
        'ICN1101-Programming': ['Lectures', 'Assignments', 'Code', 'Notes'],
        'ICN1102-Networks': ['Lectures', 'Labs', 'PacketTracer', 'Notes'],
        'ICN1103-OS': ['Lectures', 'Labs', 'Assignments'],
        'ICN1104-Architecture': ['Lectures', 'Notes', 'Diagrams']
    }

    for course, folders in courses.items():
        course_path = year / course
        for folder in folders:
            (course_path / folder).mkdir(parents=True, exist_ok=True)
        print(f'✅ Created: {course}')

    print(f'\n📁 All folders ready at: {year}')

if __name__ == '__main__':
