import psutil

def top_processes(limit=10):
    procs = []
    for p in psutil.process_iter(['pid', 'name', 'cpu_percent', 'memory_percent']):
        try:
            info = p.info
            info['mem_mb'] = p.memory_info().rss / (1024 * 1024)
            procs.append(info)
        except:
            continue
    procs.sort(key=lambda x: x['mem_mb'], reverse=True)
    return procs[:limit]

if __name__ == '__main__':
    print('Top Memory Users:\n')
    for i, p in enumerate(top_processes(), 1):
        print(f'{i}. PID:{p["pid"]:6} | {p["mem_mb"]:6.0f}MB | {p["name"]}')

class NetworkDevice:
    def __init__(self, name, ip, mac=None):
        self.name = name
        self.ip = ip
        self.mac = mac
        self.online = False

    def ping(self):
        import os
        param = '-n 1' if os.name == 'nt' else '-c 1'
        response = os.system(f'ping {param} {self.ip} > /dev/null 2>&1')
        self.online = (response == 0)
        return self.online

    def __str__(self):
        status = '🟢' if self.online else '🔴'
        return f'{status} {self.name} ({self.ip})'

class Router(NetworkDevice):
    def __init__(self, name, ip, model=None):
        super().__init__(name, ip)
        self.model = model
        self.routes = []

    def add_route(self, network, gateway):
        self.routes.append({'network': network, 'gateway': gateway})

class Switch(NetworkDevice):
    def __init__(self, name, ip, ports=24):
        super().__init__(name, ip)
        self.ports = ports
        self.mac_table = {}

if __name__ == '__main__':
    router = Router('Core-R1', '192.168.1.1', 'Cisco 2900')
    router.add_route('10.0.0.0/8', '192.168.1.254')
    print(f'Created: {router}')
    print(f'Routes: {router.routes}')

from scapy.all import sniff, IP, TCP, UDP

def analyze_packet(packet):
    if packet.haslayer(IP):
        src = packet[IP].src
        dst = packet[IP].dst
        proto = packet[IP].proto

        if packet.haslayer(TCP):
            print(f'TCP {src}:{packet[TCP].sport} -> {dst}:{packet[TCP].dport}')
        elif packet.haslayer(UDP):
            print(f'UDP {src}:{packet[UDP].sport} -> {dst}:{packet[UDP].dport}')

print('Capturing 20 packets...')
sniff(prn=analyze_packet, count=20)
print('Capture complete.')

import sqlite3

class InventoryDB:
    def __init__(self, db='inventory.db'):
        self.conn = sqlite3.connect(db)
        self.create_tables()

    def create_tables(self):
        self.conn.execute('''
            CREATE TABLE IF NOT EXISTS devices (
                id INTEGER PRIMARY KEY,
                hostname TEXT UNIQUE NOT NULL,
                ip TEXT UNIQUE NOT NULL,
                device_type TEXT,
                location TEXT,
                status TEXT DEFAULT "active"
            )
        ''')
        self.conn.commit()

    def add_device(self, hostname, ip, dtype, location):
        self.conn.execute(
            'INSERT INTO devices (hostname, ip, device_type, location) VALUES (?,?,?,?)',
            (hostname, ip, dtype, location)
        )
        self.conn.commit()
        print(f'✅ Added: {hostname}')

    def search(self, query=''):
        cursor = self.conn.execute(
            'SELECT * FROM devices WHERE hostname LIKE ? OR ip LIKE ?',
            (f'%{query}%', f'%{query}%')
        )
        return cursor.fetchall()

if __name__ == '__main__':
    db = InventoryDB()
    db.add_device('Core-SW1', '10.0.0.1', 'Switch', 'Server Room')
    for device in db.search('Core'):
        print(device)

import serial
import serial.tools.list_ports

def list_serial_ports():
    ports = serial.tools.list_ports.comports()
    print('Available ports:')
    for port in ports:
        print(f'  {port.device} — {port.description}')
    return [p.device for p in ports]

def connect_and_read(port, baud=9600):
    try:
        ser = serial.Serial(port, baud, timeout=1)
        print(f'Connected to {port}')
        for _ in range(5):
            if ser.in_waiting:
                data = ser.readline().decode().strip()
                print(f'Received: {data}')
        ser.close()
    except Exception as e:
        print(f'Error: {e}')

if __name__ == '__main__':
    ports = list_serial_ports()
    if ports:
        connect_and_read(ports[0])
